function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: [number, number][][] = Array(n).fill(0).map(() => Array<number, number>());

    for (const [u, v, cost] of edges) {
        if (online[u] && online[v]) {
            graph[u].push([v, cost]);
        }
    }

    let maxScore = -1;
    const pq: [number, number, number, number] = [(-Infinity, 0, 0, Infinity)];
    const visited: boolean[] = Array(n).fill(false);

    while (pq.length > 0) {
        const [negMinEdge, node, totalCost, minEdge] = pq.shift() as [number, number, number, number];
        const currentMinEdge = -negMinEdge;

        if (visited[node]) continue;
        visited[node] = true;

        if (node === n - 1) {
            maxScore = Math.max(maxScore, currentMinEdge);
            continue;
        }

        for (const [neighbor, edgeCost] of graph[node]) {
            const newTotal = totalCost + edgeCost;
            if (newTotal > k) continue;
            const newMinEdge = Math.min(currentMinEdge, edgeCost);
            pq.push([-newMinEdge, neighbor, newTotal, newMinEdge]);
        }
    }

    return maxScore;
}
